      cont->append(sel);
      vars.push_back({ cont });
    }
  }

  // Need complex selectors to preserve linefeeds
  std::vector<std::vector<ComplexSelectorObj>> res = permutateAlt(vars);

  // std::reverse(std::begin(res), std::end(res));

  auto lst = SASS_MEMORY_NEW(SelectorList, pstate());
